struct TapGestureDemo: View {
    @State private var tapCount = 0

    var body: some View {
        Circle()
            .fill(tapCount.isMultiple(of: 2) ? Color.blue : Color.red)
            .frame(width: 120, height: 120)
            .onTapGesture(count: {count}) {
                tapCount += 1
            }
            .accessibilityLabel("Tap target, tapped \(tapCount) times")
    }
}

struct SpatialTapDemo: View {
    @State private var location: CGPoint = .zero

    var body: some View {
        Rectangle()
            .fill(.blue.opacity(0.2))
            .frame(width: 240, height: 160)
            .overlay(alignment: .topLeading) {
                Circle().fill(.red).frame(width: 16, height: 16)
                    .position(location)
            }
            .gesture(
                SpatialTapGesture(count: {count}, coordinateSpace: {coordinateSpace})
                    .onEnded { value in location = value.location }
            )
    }
}

struct LongPressDemo: View {
    @GestureState private var isPressing = false
    @State private var completed = false

    var body: some View {
        Circle()
            .fill(completed ? .green : (isPressing ? .orange : .blue))
            .frame(width: 120, height: 120)
            .scaleEffect(isPressing ? 1.15 : 1.0)
            .gesture(
                LongPressGesture(minimumDuration: {minimumDuration}, maximumDistance: {maximumDistance})
                    .updating($isPressing) { current, state, _ in state = current }
                    .onEnded { finished in completed = finished }
            )
            .animation(.easeInOut, value: isPressing)
    }
}

struct DragDemo: View {
    @GestureState private var drag: CGSize = .zero
    @State private var offset: CGSize = .zero

    var body: some View {
        RoundedRectangle(cornerRadius: 16)
            .fill(.blue)
            .frame(width: 100, height: 100)
            .offset(x: offset.width + drag.width, y: offset.height + drag.height)
            .gesture(
                DragGesture(minimumDistance: {minimumDistance}, coordinateSpace: {coordinateSpace})
                    .updating($drag) { value, state, _ in state = value.translation }
                    .onEnded { value in
                        offset.width += value.translation.width
                        offset.height += value.translation.height
                    }
            )
    }
}

struct MagnifyDemo: View {
    @State private var scale: CGFloat = 1.0
    @GestureState private var pinch: CGFloat = 1.0

    var body: some View {
        Image(systemName: "photo")
            .resizable().scaledToFit()
            .frame(width: 160, height: 160)
            .scaleEffect(scale * pinch)
            .gesture(
                MagnifyGesture(minimumScaleDelta: {minimumScaleDelta})
                    .updating($pinch) { value, state, _ in state = value.magnification }
                    .onEnded { value in scale *= value.magnification }
            )
    }
}

struct RotateDemo: View {
    @State private var angle: Angle = .zero
    @GestureState private var spin: Angle = .zero

    var body: some View {
        Rectangle()
            .fill(.blue)
            .frame(width: 160, height: 160)
            .rotationEffect(angle + spin)
            .gesture(
                RotateGesture(minimumAngleDelta: {minimumAngleDelta})
                    .updating($spin) { value, state, _ in state = value.rotation }
                    .onEnded { value in angle += value.rotation }
            )
    }
}

#if os(visionOS)
struct Rotate3DDemo: View {
    @State private var rotation = Rotation3D.identity

    var body: some View {
        Model3D(named: "Object")
            .gesture(
                RotateGesture3D(constrainedToAxis: {constrainedToAxis}, minimumAngleDelta: {minimumAngleDelta})
                    .onChanged { value in rotation = value.rotation }
            )
    }
}
#endif

struct SpatialEventDemo: View {
    @State private var points: [SpatialEventCollection.Event.ID: CGPoint] = [:]

    var body: some View {
        Canvas { context, _ in
            for point in points.values {
                context.fill(Path(ellipseIn: CGRect(x: point.x - 8, y: point.y - 8, width: 16, height: 16)), with: .color(.blue))
            }
        }
        .gesture(
            SpatialEventGesture(coordinateSpace: {coordinateSpace})
                .onChanged { events in
                    for event in events {
                        points[event.id] = event.phase == .active ? event.location : nil
                    }
                }
                .onEnded { _ in points.removeAll() }
        )
    }
}

struct SimultaneousDemo: View {
    @State private var scale: CGFloat = 1
    @State private var angle: Angle = .zero

    var body: some View {
        Image(systemName: "photo")
            .resizable().scaledToFit()
            .frame(width: 160, height: 160)
            .scaleEffect(scale)
            .rotationEffect(angle)
            .gesture(
                {firstGesture}()
                    .simultaneously(with: {secondGesture}())
                    .onChanged { value in
                        if let m = value.first?.magnification { scale = m }
                        if let r = value.second?.rotation { angle = r }
                    }
            )
    }
}

struct SequencedDemo: View {
    @GestureState private var isActive = false
    @State private var offset: CGSize = .zero

    var body: some View {
        RoundedRectangle(cornerRadius: 16)
            .fill(isActive ? .green : .blue)
            .frame(width: 100, height: 100)
            .offset(offset)
            .gesture(
                {firstGesture}()
                    .sequenced(before: {secondGesture}())
                    .updating($isActive) { value, state, _ in
                        switch value {
                        case .second(true, _): state = true
                        default: state = false
                        }
                    }
                    .onEnded { value in
                        if case let .second(_, drag?) = value { offset = drag.translation }
                    }
            )
    }
}

struct ExclusiveDemo: View {
    @State private var label = "Idle"

    var body: some View {
        Circle()
            .fill(.blue)
            .frame(width: 120, height: 120)
            .overlay(Text(label).foregroundStyle(.white))
            .gesture(
                {firstGesture}()
                    .exclusively(before: {secondGesture}())
                    .onEnded { value in
                        switch value {
                        case .first: label = "First"
                        case .second: label = "Second"
                        }
                    }
            )
    }
}

struct GestureStateDemo: View {
    @GestureState(initialValue: {initialValue}) private var translation: CGSize
    @State private var committed: CGSize = .zero

    var body: some View {
        Circle()
            .fill(.blue)
            .frame(width: 100, height: 100)
            .offset(x: committed.width + translation.width, y: committed.height + translation.height)
            .gesture(
                DragGesture()
                    .updating($translation) { value, state, transaction in
                        state = value.translation
                        transaction.animation = {resetTransaction}
                    }
                    .onEnded { value in
                        committed.width += value.translation.width
                        committed.height += value.translation.height
                    }
            )
    }
}

struct GestureModifierDemo: View {
    @State private var taps = 0

    var body: some View {
        Rectangle()
            .fill(.blue.opacity(0.3))
            .frame(width: 200, height: 200)
            .overlay(Text("\(taps)"))
            .{priority}(
                TapGesture().onEnded { taps += 1 },
                including: {mask}
            )
    }
}

struct DeferSystemGesturesDemo: View {
    var body: some View {
        Color.black
            .ignoresSafeArea()
            .gesture(DragGesture().onChanged { _ in })
            .defersSystemGestures(on: {edges})
    }
}

struct WindowDragDemo: View {
    @GestureState private var isDragging = false

    var body: some View {
        Circle()
            .fill(isDragging ? Color.green : .blue)
            .frame(width: 80, height: 80)
            .gesture(
                WindowDragGesture()
                    .updating($isDragging) { _, state, _ in state = true }
            )
            .allowsWindowActivationEvents({allowsWindowActivationEvents})
    }
}

struct PencilGestureDemo: View {
    @Environment(\.preferredPencilDoubleTapAction) private var preferred
    @State private var label = "Idle"

    var body: some View {
        RoundedRectangle(cornerRadius: 16)
            .fill(.blue.opacity(0.2))
            .frame(width: 240, height: 160)
            .overlay(Text(label))
            .onPencilDoubleTap { _ in
                guard preferred != .ignore else { return }
                label = "Double-tapped"
            }
            .onPencilSqueeze { phase in
                if case .ended = phase { label = "Squeezed" }
            }
    }
}

#if os(tvOS)
struct LongTouchDemo: View {
    @State private var touching = false
    @State private var fired = false

    var body: some View {
        Circle()
            .fill(fired ? .green : (touching ? .orange : .blue))
            .frame(width: 160, height: 160)
            .onLongTouchGesture(minimumDuration: {minimumDuration}) {
                fired = true
            } onTouchingChanged: { isTouching in
                touching = isTouching
            }
    }
}
#endif

struct HandGestureShortcutDemo: View {
    @State private var playing = false

    var body: some View {
        Button(playing ? "Pause" : "Play") {
            playing.toggle()
        }
        .handGestureShortcut({shortcut}, isEnabled: {isEnabled})
    }
}
